import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.ePeAWSvT.js";const i="/assets/data-model-related-data.Dy2SkESB.png",g=JSON.parse('{"title":"Related Data","description":"","frontmatter":{},"headers":[],"relativePath":"guide/reference-related-data.md","filePath":"guide/reference-related-data.md"}'),n={name:"guide/reference-related-data.md"};function s(l,e,d,p,c,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="related-data" tabindex="-1">Related Data <a class="header-anchor" href="#related-data" aria-label="Permalink to &quot;Related Data&quot;">​</a></h1><p>Related Data is a mechanism that allows properties from <strong>related entities</strong> to be included alongside the primary entity during synchronization events. Rather than only syncing the direct properties of an entity (e.g. a Sales Order&#39;s own fields), Related Data lets you carry forward attributes from linked entities (e.g. the Customer&#39;s name or a Location&#39;s address) so that subscribing systems have the context they need without performing separate lookups.</p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>When an entity is published through Central, it carries a collection of Related Data items alongside its own properties. Each item is identified by three attributes:</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Description</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>The Common Name or property name of the data (e.g. <code>CompanyName</code>, <code>LocationCode</code>)</td></tr><tr><td><strong>System</strong></td><td>The source system the value originated from (e.g. <code>SystemA</code>, <code>SystemB</code>)</td></tr><tr><td><strong>Related Key Name</strong></td><td>The foreign key relationship this data was resolved through (e.g. <code>CompanyId</code>, <code>LocationId</code>). When blank, the data belongs to the entity itself.</td></tr></tbody></table><p>This three-part key means the same property name can exist multiple times in an entity&#39;s related data — once per source system and relationship — without conflict.</p><div class="info custom-block"><p class="custom-block-title">Example</p><p>A Sales Order entity might carry the following related data:</p><table tabindex="0"><thead><tr><th>Name</th><th>System</th><th>Related Key Name</th><th>Value</th></tr></thead><tbody><tr><td><code>CompanyName</code></td><td>ERP-A</td><td><code>CompanyId</code></td><td>Acme Corp</td></tr><tr><td><code>CompanyName</code></td><td>CRM-B</td><td><code>CompanyId</code></td><td>ACME Corporation</td></tr><tr><td><code>LocationCode</code></td><td>ERP-A</td><td><code>LocationId</code></td><td>WH-01</td></tr></tbody></table><p>Each value is tagged with the system it came from and the foreign key it was resolved through.</p></div><h2 id="accumulation-during-sync" tabindex="-1">Accumulation During Sync <a class="header-anchor" href="#accumulation-during-sync" aria-label="Permalink to &quot;Accumulation During Sync&quot;">​</a></h2><p>Related Data is <strong>accumulated automatically</strong> during the sync pipeline. When Central resolves foreign key relationships for an entity, it copies relevant properties from the related core entities into the Related Data collection:</p><ol><li><p><strong>Foreign key resolution</strong> — Central looks up the core entity referenced by each foreign key on the integration entity (e.g. resolving a <code>CompanyId</code> to a Company record).</p></li><li><p><strong>Property copying</strong> — Properties marked as Related Data on the related entity&#39;s schema are copied into the current entity&#39;s Related Data collection, tagged with the foreign key name they came from.</p></li><li><p><strong>Extra key accumulation</strong> — If the related entity has Extra Primary Keys, those are also accumulated as Related Data items so subscribing systems can use alternate identifiers.</p></li><li><p><strong>Cascading to children</strong> — When an entity has child endpoints, the parent&#39;s Related Data (from its own properties, not from other relationships) is cascaded down to child entities, tagged with the parent&#39;s foreign key name.</p></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Related Data accumulation is automatic once schema properties are flagged. You do not need to write custom code or configure additional pipeline steps — just mark the properties and map them.</p></div><h2 id="configuring-related-data" tabindex="-1">Configuring Related Data <a class="header-anchor" href="#configuring-related-data" aria-label="Permalink to &quot;Configuring Related Data&quot;">​</a></h2><p>There are two places where Related Data is configured: <strong>Data Models</strong> (which properties to include) and <strong>Action Mapping</strong> (how to map them to connector payloads).</p><h3 id="_1-flagging-properties-in-data-models" tabindex="-1">1. Flagging Properties in Data Models <a class="header-anchor" href="#_1-flagging-properties-in-data-models" aria-label="Permalink to &quot;1. Flagging Properties in Data Models&quot;">​</a></h3><p>To make a schema property available as Related Data for other entities:</p><ol><li>Navigate to <strong>Build</strong> &gt; <strong>Data Models</strong> and edit the Schema Definition that owns the property.</li><li>On the <strong>Simple</strong> tab, select the <strong>edit</strong> icon for the property you want to include.</li><li>Toggle <strong>Related Data</strong> to ON, then select <strong>Save</strong>.</li></ol><p><img src="'+i+'" alt="Data Model with Related Data flags"></p><p>Once enabled, this property will be accumulated into any entity that has a foreign key relationship pointing to this schema&#39;s entity type. The Related Data flag appears as a green checkmark (<i class="fa fa-check text-success"></i>) in the property grid.</p><p>For more details on editing schema properties, see <a href="./build-data-models.html">Data Models</a>.</p><h3 id="_2-mapping-related-data-properties" tabindex="-1">2. Mapping Related Data Properties <a class="header-anchor" href="#_2-mapping-related-data-properties" aria-label="Permalink to &quot;2. Mapping Related Data Properties&quot;">​</a></h3><p>When mapping an endpoint action (typically a <strong>save/subscribe</strong> action), Related Data properties appear as selectable options in the Central Property picker alongside the entity&#39;s own properties.</p><p>Related Data properties are displayed with a label indicating the relationship they come from:</p><blockquote><p><code>CompanyName (From CompanyId)</code></p></blockquote><p>This tells you the <code>CompanyName</code> value is resolved through the entity&#39;s <code>CompanyId</code> foreign key.</p><p>To map a Related Data property:</p><ol><li>Navigate to the endpoint&#39;s <strong>Action Mapping</strong> screen.</li><li>Add or edit a map element.</li><li>In the <strong>Central Property</strong> picker, look for properties grouped under their source relationship. These are the Related Data properties accumulated from related entities.</li><li>Select the desired property — the mapping engine will read the value from the entity&#39;s Related Data collection at sync time.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Related Data properties are available in <strong>save/subscribe</strong> actions only. They do not appear in read/publish actions because the data has not yet been accumulated at that point in the pipeline.</p></div><p>For more details on action mapping, see <a href="./datahub-action-mapping.html">Action Mapping</a>.</p><h2 id="when-to-use-related-data" tabindex="-1">When to Use Related Data <a class="header-anchor" href="#when-to-use-related-data" aria-label="Permalink to &quot;When to Use Related Data&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Best Practice</p><p>Use Related Data when a subscribing system needs context from a related entity that it cannot look up on its own.</p></div><p><strong>Common scenarios:</strong></p><ul><li><strong>Denormalized saves</strong> — A target system expects the customer name on the sales order payload, not just the customer ID. Map the <code>CompanyName</code> Related Data property directly onto the connector&#39;s save payload.</li><li><strong>Alternate identifiers</strong> — A target system uses a different ID for the same entity. Extra Primary Keys from the related entity are accumulated as Related Data, so you can map the alternate ID without a separate lookup.</li><li><strong>Cascading context</strong> — Child entities (e.g. order lines) need access to parent-level attributes (e.g. order type, warehouse code). The parent&#39;s Related Data is cascaded to children automatically.</li></ul><p><strong>When NOT to use Related Data:</strong></p><ul><li>If the subscribing connector can resolve the reference itself (e.g. it only needs the foreign key ID), a standard Foreign Key mapping is sufficient.</li><li>If the data is specific to the current entity (not from a relationship), use a regular Property mapping instead.</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./build-data-models.html">Data Models</a> — Define schemas and flag properties as Related Data</li><li><a href="./datahub-action-mapping.html">Action Mapping</a> — Map Related Data properties to connector payloads</li><li><a href="./datahub-relationships.html">Endpoint Relationships</a> — Configure parent/child and dependent publisher relationships</li><li><a href="./reference-common-model.html">Common Model Definitions</a> — Central Property definitions used in schema mapping</li></ul>',36)])])}const u=t(n,[["render",s]]);export{g as __pageData,u as default};
